// // This module implements a 4-bit MD5-like hash function that takes a 4-bit input and produces a 4-bit output. The output is computed by performing an AND operation on the input bits and a fixed constant value. The constant value is 4'b1010.
module md5_hash (
    input wire clk,
    input wire reset,
    input wire [3:0] data_in,
    output reg [3:0] hash_out
);

    parameter CONSTANT = 4'b1010;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            hash_out <= 4'b0000;
        end else begin
            hash_out <= data_in ^ CONSTANT;
        end
    end

endmodule
